 14	const getGroupId = (groupKey: PinnedGroupKey): string => `${groupKey.shotId}:${groupKey.trackId}`;
 15	
 16	const countMatchingClipIds = (row: TimelineRow | undefined, clipIds: readonly string[]): number => {
 17	  if (!row || clipIds.length === 0) {
 18	    return 0;
 19	  }
 20	
 21	  const rowClipIds = new Set(row.actions.map((action) => action.id));
 22	  let matches = 0;
 23	  for (const clipId of clipIds) {
 24	    if (rowClipIds.has(clipId)) {
 25	      matches += 1;
 26	    }
 27	  }
 28	
 29	  return matches;
 30	};
 31	
 32	export function resolveGroupTrackId(group: PinnedShotGroup, rows: TimelineRow[]): string {
 33	  const storedRow = rows.find((row) => row.id === group.trackId);
 34	  const storedMatchCount = countMatchingClipIds(storedRow, group.clipIds);
 35	
 36	  // Fast path: every live clip still sits on the stored row.
 37	  if (storedMatchCount === group.clipIds.length && storedMatchCount > 0) {
 38	    return group.trackId;
 39	  }
 40	
 41	  let bestTrackId = storedMatchCount > 0 ? group.trackId : '';
 42	  let bestMatchCount = storedMatchCount;
 43	
 44	  for (const row of rows) {
 45	    if (row.id === group.trackId) {
 46	      continue;
 47	    }
 48	
 49	    const matchCount = countMatchingClipIds(row, group.clipIds);
 50	    if (matchCount > bestMatchCount) {
 51	      bestMatchCount = matchCount;
 52	      bestTrackId = row.id;
 53	    }
 54	  }
 55	
 56	  return bestMatchCount > 0 ? bestTrackId : group.trackId;
 57	}
