 59	export function findGroupForTrack(
 60	  groups: PinnedShotGroup[],
 61	  shotId: string,
 62	  trackId: string,
 63	  rows: TimelineRow[],
 64	): PinnedShotGroup | undefined {
 65	  const exactMatch = groups.find((group) => group.shotId === shotId && group.trackId === trackId);
 66	  if (exactMatch) {
 67	    const exactResolvedTrackId = resolveGroupTrackId(exactMatch, rows);
 68	    if (exactResolvedTrackId === trackId) {
 69	      return exactMatch;
 70	    }
 71	
 72	    const resolvedMatch = groups.find(
 73	      (group) => group.shotId === shotId && resolveGroupTrackId(group, rows) === trackId,
 74	    );
 75	    return resolvedMatch ?? exactMatch;
 76	  }
 77	
 78	  return groups.find(
 79	    (group) => group.shotId === shotId && resolveGroupTrackId(group, rows) === trackId,
 80	  );
 81	}
