 83	/**
 84	 * Find the pinned group that contains `clipId`, if any. Soft-tag lookup only —
 85	 * returns the first group whose `clipIds` list includes the target.
 86	 */
 87	export function findEnclosingPinnedGroup(
 88	  config: TimelineConfig,
 89	  clipId: string,
 90	): { group: PinnedShotGroup; groupKey: PinnedGroupKey; index: number } | null {
 91	  const groups = config.pinnedShotGroups ?? [];
 92	  const index = groups.findIndex((group) => group.clipIds.includes(clipId));
 93	  if (index < 0) {
 94	    return null;
 95	  }
 96	
 97	  const group = groups[index];
 98	  return {
 99	    group,
100	    groupKey: { shotId: group.shotId, trackId: group.trackId },
101	    index,
102	  };
103	}
