105	/**
106	 * Split a selection of clip ids into free clips and enclosing groups. If any
107	 * clip in the selection belongs to a group, the group's full `clipIds` list is
108	 * used (selection expands to the whole group).
109	 */
110	export function categorizeSelection(
111	  clipIds: string[],
112	  config: TimelineConfig,
113	): CategorizedSelection {
114	  const uniqueClipIds = [...new Set(clipIds)];
115	  const freeClipIds: string[] = [];
116	  const groups = new Map<string, { groupKey: PinnedGroupKey; clipIds: string[] }>();
117	
118	  for (const clipId of uniqueClipIds) {
119	    const enclosingGroup = findEnclosingPinnedGroup(config, clipId);
120	    if (!enclosingGroup) {

180	
181	      let workingData = latest;
182	      let workingPinnedShotGroups = (latest.config.pinnedShotGroups ?? []).map(clonePinnedShotGroup);
183	      const accumulatedMetaUpdates: Record<string, ClipMeta> = {};
184	      const accumulatedMetaDeletes = new Set<string>();
185	      let hasChanges = false;
186	
187	      for (const group of workingPinnedShotGroups) {
188	        if (group.mode !== 'images') {
189	          continue;
190	        }
191	
192	        const resolvedTrackId = resolveGroupTrackId(group, workingData.rows);
193	        const storedTrackId = group.trackId;
194	
195	        const shot = shots.find((candidate) => candidate.id === group.shotId);
196	        const desiredImages = getSyncableShotImages(shot);
197	        const desiredGenerationIds = desiredImages
198	          .map((image) => image.generation_id)
199	          .filter((generationId): generationId is string => typeof generationId === 'string' && generationId.length > 0);
200	
201	        const targetRowIndex = workingData.rows.findIndex((row) => row.id === resolvedTrackId);
202	        if (targetRowIndex < 0) {
203	          continue;
204	        }
205	
206	        const targetRow = workingData.rows[targetRowIndex];
207	        const orderedCurrentClipIds = orderClipIdsByAt(group.clipIds, { rows: [targetRow] });
208	        const currentGenerationIds = orderedCurrentClipIds
209	          .map((clipId) => getClipGenerationId(workingData, clipId))
210	          .filter((generationId): generationId is string => typeof generationId === 'string' && generationId.length > 0);
211	
212	        if (areStringArraysEqual(currentGenerationIds, desiredGenerationIds)) {
213	          continue;
214	        }
215	
216	        const groupActions = targetRow.actions.filter((action) => group.clipIds.includes(action.id));
217	        if (groupActions.length === 0) {
218	          continue;
219	        }
220	
221	        const firstGroupAction = targetRow.actions.findIndex((action) => action.id === groupActions[0]?.id);
222	        const lastGroupAction = targetRow.actions.findIndex((action) => action.id === groupActions[groupActions.length - 1]?.id);
223	        if (firstGroupAction < 0 || lastGroupAction < 0) {
224	          continue;
225	        }
226	
227	        const beforeActions = targetRow.actions.slice(0, firstGroupAction);
228	        const afterActions = targetRow.actions.slice(lastGroupAction + 1);
229	        const beforeActionIds = new Set(beforeActions.map((action) => action.id));
230	        const afterActionIds = new Set(afterActions.map((action) => action.id));
231	        const originalGroupEnd = groupActions[groupActions.length - 1]?.end ?? groupActions[0].end;
232	        const averageDuration = getAverageDuration(groupActions);
233	        const groupActionById = new Map(groupActions.map((action) => [action.id, action]));
234	        const availableClipIds = [...orderedCurrentClipIds];
235	
236	        let groupWorkingData: TimelineData = {
237	          ...workingData,
238	          rows: workingData.rows.map((row, rowIndex) => (
239	            rowIndex === targetRowIndex
240	              ? { ...row, actions: [...beforeActions] }
241	              : row
242	          )),
243	          clipOrder: {
244	            ...workingData.clipOrder,
245	            [resolvedTrackId]: (workingData.clipOrder[resolvedTrackId] ?? []).filter((clipId) => beforeActionIds.has(clipId)),
246	          },
247	        };
248	
249	        const nextGroupClipIds: string[] = [];
250	        const usedClipIds = new Set<string>();
251	        let cursor = groupActions[0]?.start ?? 0;
252	
253	        for (const desiredImage of desiredImages) {
254	          const desiredGenerationId = desiredImage.generation_id;
255	          const imageUrl = getMediaUrl(desiredImage);
256	          if (typeof desiredGenerationId !== 'string' || desiredGenerationId.length === 0) {
257	            continue;
258	          }
259	          if (!imageUrl) {
260	            continue;
261	          }
262	
263	          const reusableClipId = availableClipIds.find((clipId) => (
264	            !usedClipIds.has(clipId)
265	            && getClipGenerationId(workingData, clipId) === desiredGenerationId
266	          ));
267	
268	          if (reusableClipId) {
269	            const sourceAction = groupActionById.get(reusableClipId);
270	            const duration = sourceAction
271	              ? Math.max(0.05, sourceAction.end - sourceAction.start)
272	              : averageDuration;
273	            const action: TimelineAction = {
274	              id: reusableClipId,
275	              start: cursor,
276	              end: cursor + duration,
277	              effectId: `effect-${reusableClipId}`,
278	            };
279	            groupWorkingData = appendActionToTrack({
280	              current: groupWorkingData,
281	              trackId: resolvedTrackId,
282	              action,
283	            });
284	            nextGroupClipIds.push(reusableClipId);
285	            usedClipIds.add(reusableClipId);
286	            cursor = action.end;
287	            continue;
288	          }
289	
290	          const assetKey = registerGenerationAsset({
291	            generationId: desiredGenerationId,
292	            variantType: 'image',
293	            imageUrl,
294	            thumbUrl: getThumbnailUrl(desiredImage) ?? imageUrl,
295	            metadata: {
296	              content_type: desiredImage.contentType ?? desiredImage.type ?? 'image/png',
297	            },
298	          });
299	          if (!assetKey) {
300	            continue;
301	          }
302	
303	          const latestRegistryEntry = dataRef.current?.registry.assets[assetKey];
304	          if (latestRegistryEntry) {
305	            groupWorkingData = {
306	              ...groupWorkingData,
307	              registry: {
308	                ...groupWorkingData.registry,
309	                assets: {
310	                  ...groupWorkingData.registry.assets,
311	                  [assetKey]: latestRegistryEntry,
312	                },
313	              },
314	            };
315	          }
316	
317	          const nextEdit = buildAssetDropEdit({
318	            current: groupWorkingData,
319	            assetKey,
320	            trackId: resolvedTrackId,
321	            time: cursor,
322	          });
323	          if (!nextEdit) {
324	            continue;
325	          }
326	
327	          Object.assign(accumulatedMetaUpdates, nextEdit.metaUpdates);
328	          nextGroupClipIds.push(nextEdit.clipId);
329	          cursor += nextEdit.duration;
330	          groupWorkingData = {
331	            ...groupWorkingData,
332	            rows: nextEdit.rows,
333	            meta: {
334	              ...groupWorkingData.meta,
335	              ...nextEdit.metaUpdates,
336	            },
337	            clipOrder: nextEdit.clipOrderOverride,
338	          };
339	        }
340	
341	        const removedClipIds = group.clipIds.filter((clipId) => !nextGroupClipIds.includes(clipId));
342	        for (const clipId of removedClipIds) {
343	          accumulatedMetaDeletes.add(clipId);
344	        }
345	
346	        const afterShift = cursor - originalGroupEnd;
347	        const shiftedAfterActions = afterActions.map((action) => ({
348	          ...action,
349	          start: action.start + afterShift,
350	          end: action.end + afterShift,
351	        }));
352	        const rebuiltRow = groupWorkingData.rows[targetRowIndex];
353	        const nextRows = groupWorkingData.rows.map((row, rowIndex) => (
354	          rowIndex === targetRowIndex
355	            ? { ...row, actions: [...rebuiltRow.actions, ...shiftedAfterActions] }
356	            : row
357	        ));
358	        const nextClipOrder = {
359	          ...groupWorkingData.clipOrder,
360	          [resolvedTrackId]: [
361	            ...(groupWorkingData.clipOrder[resolvedTrackId] ?? []),
362	            ...(workingData.clipOrder[resolvedTrackId] ?? []).filter((clipId) => afterActionIds.has(clipId)),
363	          ],
364	        };
365	        const orderedNextGroupClipIds = orderClipIdsByAt(nextGroupClipIds, { rows: nextRows });
366	        const nextGroups = workingPinnedShotGroups
367	          .map((candidate) => (
368	            candidate.shotId === group.shotId && candidate.trackId === storedTrackId
369	              ? {
370	                  ...clonePinnedShotGroup(candidate),
371	                  ...(resolvedTrackId !== storedTrackId ? { trackId: resolvedTrackId } : {}),
372	                  clipIds: orderedNextGroupClipIds,
373	                }
374	              : clonePinnedShotGroup(candidate)
375	          ))
376	          .filter((candidate) => (
377	            candidate.shotId !== group.shotId
378	            || (candidate.trackId !== storedTrackId && candidate.trackId !== resolvedTrackId)
379	            || candidate.clipIds.length > 0
380	          ));
381	
382	        workingPinnedShotGroups = nextGroups;
383	        workingData = {
384	          ...groupWorkingData,
385	          config: {
386	            ...groupWorkingData.config,
387	            pinnedShotGroups: nextGroups,
388	          },
389	          rows: nextRows,
390	          clipOrder: nextClipOrder,
391	        };
392	        hasChanges = true;
393	      }
394	
395	      if (!hasChanges) {
396	        return;
397	      }
398	
399	      const contiguousRows = ensureGroupContiguity(workingData.rows, workingPinnedShotGroups);
400	
401	      applyEdit({
402	        type: 'rows',
403	        rows: contiguousRows,
404	        metaUpdates: Object.keys(accumulatedMetaUpdates).length > 0 ? accumulatedMetaUpdates : undefined,
405	        metaDeletes: accumulatedMetaDeletes.size > 0 ? [...accumulatedMetaDeletes] : undefined,
406	        clipOrderOverride: workingData.clipOrder,
407	        pinnedShotGroupsOverride: workingPinnedShotGroups,
408	      });
409	    };
