198	function getClipDuration(meta: ClipMeta, action: TimelineAction): number {
199	  if (typeof meta.hold === 'number' && Number.isFinite(meta.hold) && meta.hold > 0) {
200	    return meta.hold;
201	  }
202	
203	  if (
204	    typeof meta.from === 'number'
205	    && typeof meta.to === 'number'
206	    && Number.isFinite(meta.from)
207	    && Number.isFinite(meta.to)
208	    && meta.to > meta.from
209	  ) {
210	    return Math.max(0.05, (meta.to - meta.from) / Math.max(meta.speed ?? 1, 0.01));
211	  }
212	
213	  return Math.max(0.05, action.end - action.start);
214	}
