242	export function buildSwitchShotGroupToFinalVideoMutation({
243	  currentData,
244	  shotId,
245	  rowId,
246	  clipIds,
247	  assetKey,
248	}: {
249	  currentData: TimelineData | null;
250	  shotId: string;
251	  rowId: string;
252	  clipIds: string[];
253	  assetKey: string;
254	}) {
255	  if (!currentData || clipIds.length === 0) {
256	    return null;
257	  }
258	
259	  const existingPinnedGroups = currentData.config.pinnedShotGroups ?? [];
260	  const pinnedGroup = findGroupForTrack(existingPinnedGroups, shotId, rowId, currentData.rows);
261	  const resolvedTrackId = pinnedGroup ? resolveGroupTrackId(pinnedGroup, currentData.rows) : rowId;
262	  const sourceClipIds = pinnedGroup?.mode === 'images' ? pinnedGroup.clipIds : clipIds;
263	  const clipIdSet = new Set(sourceClipIds);
264	  const targetRow = currentData.rows.find((row) => row.id === resolvedTrackId);
265	  if (!targetRow) {
266	    return null;
267	  }
268	
269	  const imageActions = targetRow.actions.filter((action) => clipIdSet.has(action.id));
270	  if (imageActions.length !== sourceClipIds.length) {
271	    return null;
272	  }
273	
274	  const startTime = Math.min(...imageActions.map((action) => action.start));
275	  const endTime = Math.max(...imageActions.map((action) => action.end));
276	  if (!Number.isFinite(startTime) || !Number.isFinite(endTime) || endTime <= startTime) {
277	    return null;
278	  }
279	
280	  const imageClipSnapshot = sourceClipIds.flatMap((sourceClipId) => {
281	    const sourceMeta = currentData.meta[sourceClipId];
282	    const sourceAction = imageActions.find((action) => action.id === sourceClipId);
283	    if (!sourceMeta || !sourceAction) {
284	      return [];
285	    }
286	
287	    return [{
288	      clipId: sourceClipId,
289	      assetKey: sourceMeta.asset,
290	      start: sourceAction.start,
291	      end: sourceAction.end,
292	      meta: snapshotClipMeta(sourceMeta),
293	    }];
294	  });
295	  if (imageClipSnapshot.length !== sourceClipIds.length) {
296	    return null;
297	  }
298	
299	  const videoClipId = getNextClipId(currentData.meta);
300	  const targetTrack = currentData.tracks.find((track) => track.id === resolvedTrackId);
301	  const isManualVisualTrack = targetTrack?.kind === 'visual' && targetTrack.fit === 'manual';
302	  const duration = endTime - startTime;
303	  const videoMeta: ClipMeta = {
304	    asset: assetKey,
305	    track: resolvedTrackId,
306	    clipType: 'media',
307	    from: 0,
308	    to: duration,
309	    speed: 1,
310	    volume: 1,
311	    opacity: 1,
312	    x: isManualVisualTrack ? 100 : undefined,
313	    y: isManualVisualTrack ? 100 : undefined,
314	    width: isManualVisualTrack ? 320 : undefined,
315	    height: isManualVisualTrack ? 240 : undefined,
316	  };
317	  const videoAction: TimelineAction = {
318	    id: videoClipId,
319	    start: startTime,
320	    end: startTime + duration,
321	    effectId: `effect-${videoClipId}`,
322	  };
323	
324	  const insertionIndex = targetRow.actions.findIndex((action) => clipIdSet.has(action.id));
325	  const nextRows = currentData.rows.map((row) => {
326	    const remainingActions = row.actions.filter((action) => !clipIdSet.has(action.id));
327	    if (row.id !== resolvedTrackId) {
328	      return remainingActions.length === row.actions.length ? row : { ...row, actions: remainingActions };
329	    }
330	
331	    const nextActions = insertionIndex < 0
332	      ? [...remainingActions, videoAction]
333	      : [...remainingActions.slice(0, insertionIndex), videoAction, ...remainingActions.slice(insertionIndex)];
334	    return { ...row, actions: nextActions };
335	  });
336	  const nextClipOrder = updateClipOrder(currentData.clipOrder, resolvedTrackId, (ids) => {
337	    const filtered = ids.filter((id) => !clipIdSet.has(id));
338	    const orderInsertionIndex = ids.findIndex((id) => clipIdSet.has(id));
339	    return orderInsertionIndex < 0
340	      ? [...filtered, videoClipId]
341	      : [...filtered.slice(0, orderInsertionIndex), videoClipId, ...filtered.slice(orderInsertionIndex)];
342	  });
343	
344	  return {
345	    type: 'rows' as const,
346	    rows: nextRows,
347	    metaUpdates: { [videoClipId]: videoMeta },
348	    metaDeletes: sourceClipIds,
349	    clipOrderOverride: nextClipOrder,
350	    pinnedShotGroupsOverride: buildPinnedShotGroupsOverride(currentData, {
351	      shotId,
352	      trackId: resolvedTrackId,
353	      clipIds: [videoClipId],
354	      mode: 'video',
355	      videoAssetKey: assetKey,
356	      imageClipSnapshot,
357	    }),
358	  };
359	}
