414	export function buildSwitchShotGroupToImagesMutation({
415	  currentData,
416	  shotId,
417	  rowId,
418	}: {
419	  currentData: TimelineData | null;
420	  shotId: string;
421	  rowId: string;
422	}) {
423	  if (!currentData) {
424	    return null;
425	  }
426	
427	  const existingPinnedGroups = currentData.config.pinnedShotGroups ?? [];
428	  const foundGroup = findGroupForTrack(existingPinnedGroups, shotId, rowId, currentData.rows);
429	  const pinnedGroup = foundGroup?.mode === 'video' ? foundGroup : undefined;
430	  const resolvedTrackId = pinnedGroup ? resolveGroupTrackId(pinnedGroup, currentData.rows) : rowId;
431	  const targetRow = currentData.rows.find((row) => row.id === resolvedTrackId);
432	  const videoClipId = pinnedGroup?.clipIds[0];
433	  const videoActionIndex = targetRow?.actions.findIndex((action) => action.id === videoClipId) ?? -1;
434	  const videoAction = videoActionIndex >= 0 ? targetRow?.actions[videoActionIndex] : undefined;
435	  if (!pinnedGroup || !targetRow || !videoClipId || !videoAction || !pinnedGroup.imageClipSnapshot?.length) {
436	    return null;
437	  }
438	
439	  const restoredMetaUpdates: Record<string, ClipMeta> = {};
440	  let cursor = videoAction.start;
441	  const restoredActions = pinnedGroup.imageClipSnapshot.map((snapshot) => {
442	    const clipMeta: ClipMeta = {
443	      ...snapshot.meta,
444	      asset: snapshot.assetKey,
445	      track: resolvedTrackId,
446	    };
447	    restoredMetaUpdates[snapshot.clipId] = clipMeta;
448	    const duration = getClipDuration(clipMeta, videoAction);
449	    const start = typeof snapshot.start === 'number' ? snapshot.start : cursor;
450	    const end = typeof snapshot.end === 'number' ? snapshot.end : start + duration;
451	    cursor = end;
452	
453	    return {
454	      id: snapshot.clipId,
455	      start,
456	      end,
457	      effectId: `effect-${snapshot.clipId}`,
458	    };
459	  });
460	  const orderedRestoredActions = [...restoredActions].sort((left, right) => {
461	    if (left.start !== right.start) {
462	      return left.start - right.start;
463	    }
464	    return left.id.localeCompare(right.id);
465	  });
466	  const restoredClipIds = orderedRestoredActions.map((action) => action.id);
467	  const nextRows = currentData.rows.map((row) => {
468	    if (row.id !== resolvedTrackId) {
469	      return row;
470	    }
471	
472	    const remainingActions = row.actions.filter((action) => action.id !== videoClipId);
473	    return {
474	      ...row,
475	      actions: [
476	        ...remainingActions.slice(0, videoActionIndex),
477	        ...orderedRestoredActions,
478	        ...remainingActions.slice(videoActionIndex),
479	      ],
480	    };
481	  });
482	  const nextClipOrder = updateClipOrder(currentData.clipOrder, resolvedTrackId, (ids) => {
483	    const filtered = ids.filter((id) => id !== videoClipId);
484	    const insertionIndex = ids.indexOf(videoClipId);
485	    return insertionIndex < 0
486	      ? [...filtered, ...restoredClipIds]
487	      : [...filtered.slice(0, insertionIndex), ...restoredClipIds, ...filtered.slice(insertionIndex)];
488	  });
