503	    metaDeletes: [videoClipId],
504	    clipOrderOverride: nextClipOrder,
505	    pinnedShotGroupsOverride: nextPinnedShotGroups,
506	  };
507	}

 90	function translateGroupMembers({
 91	  current,
 92	  group,
 93	  targetRowId,
 94	  deltaTime,
 95	}: {
 96	  current: TimelineData;
 97	  group: PinnedShotGroup;
 98	  targetRowId: string;
 99	  deltaTime: number;
100	}): {
101	  nextRows: TimelineRow[];
102	  metaUpdates: Record<string, Partial<TimelineData['meta'][string]>>;
103	  nextClipOrder: TimelineData['clipOrder'];
104	  pinnedShotGroupsOverride: PinnedShotGroup[];
105	} {
106	  const memberSet = new Set(group.clipIds);
107	  const sourceTrackId = group.trackId;
108	  const storedGroup = findGroupForTrack(
109	    current.config.pinnedShotGroups ?? [],
110	    group.shotId,
111	    sourceTrackId,
112	    current.rows,
113	  );
114	  const storedTrackId = storedGroup?.trackId ?? sourceTrackId;
115	
116	  // Capture each member's current action so we can translate it.
117	  const memberActions = new Map<string, { start: number; end: number; effectId: string }>();
118	  for (const row of current.rows) {
119	    for (const action of row.actions) {
120	      if (memberSet.has(action.id)) {
121	        memberActions.set(action.id, { start: action.start, end: action.end, effectId: action.effectId });
122	      }
123	    }
124	  }
125	
126	  // Remove members from their current rows, then add them (translated) to the target row.
127	  let nextRows = current.rows.map((row) => ({
128	    ...row,
129	    actions: row.actions.filter((a) => !memberSet.has(a.id)),
130	  }));
131	  const translatedActions = group.clipIds
132	    .map((clipId) => {
133	      const original = memberActions.get(clipId);
134	      if (!original) return null;
135	      return {
136	        id: clipId,
137	        start: original.start + deltaTime,
138	        end: original.end + deltaTime,
139	        effectId: original.effectId,
140	      };
141	    })
142	    .filter((a): a is NonNullable<typeof a> => a !== null);
143	
144	  nextRows = nextRows.map((row) => (
145	    row.id === targetRowId
146	      ? { ...row, actions: [...row.actions, ...translatedActions] }
147	      : row
148	  ));
149	
150	  // Cross-track move: update each member's `track` meta patch and clip order.
151	  const metaUpdates: Record<string, Partial<TimelineData['meta'][string]>> = {};
152	  let nextClipOrder = current.clipOrder;
153	  if (sourceTrackId !== targetRowId) {
154	    for (const clipId of group.clipIds) {
155	      metaUpdates[clipId] = { track: targetRowId };
156	      nextClipOrder = moveClipBetweenTracks(nextClipOrder, clipId, sourceTrackId, targetRowId);
157	    }
158	  }
159	
160	  // Soft-tag override: trackId updated, clipIds re-derived from the translated
161	  // positions (order preserved for the trivial same-delta case, but reads from
162	  // nextRows so any future resolveOverlaps shuffles are honored).
163	  const orderedClipIds = orderClipIdsByAt(group.clipIds, { rows: nextRows });
164	  const pinnedShotGroupsOverride = (current.config.pinnedShotGroups ?? []).map((g) => (
165	    g.shotId === group.shotId && g.trackId === storedTrackId
166	      ? { ...g, trackId: targetRowId, clipIds: orderedClipIds }
167	      : g
168	  ));
169	
170	  return { nextRows, metaUpdates, nextClipOrder, pinnedShotGroupsOverride };
171	}
