173	function getLiveGroupStart(current: Pick<TimelineData, 'rows'>, group: PinnedShotGroup): number | null {
174	  const actionStarts = current.rows
175	    .flatMap((row) => row.actions)
176	    .filter((action) => group.clipIds.includes(action.id))
177	    .map((action) => action.start);
178	
179	  if (actionStarts.length === 0) {
180	    return null;
181	  }
182	
183	  return Math.min(...actionStarts);
184	}
