186	function getLiveGroupEnd(current: Pick<TimelineData, 'rows'>, group: PinnedShotGroup): number | null {
187	  const actionEnds = current.rows
188	    .flatMap((row) => row.actions)
189	    .filter((action) => group.clipIds.includes(action.id))
190	    .map((action) => action.end);
191	
192	  if (actionEnds.length === 0) {
193	    return null;
194	  }
195	
196	  return Math.max(...actionEnds);
