199	export function useTimelineTrackManagement({
200	  dataRef,
201	  resolvedConfig,
202	  selectedClipId,
203	  setSelectedTrackId,
204	  applyEdit,
205	}: UseTimelineTrackManagementArgs): UseTimelineTrackManagementResult {
206	  const moveClipToRow = useCallback((
207	    clipId: string,
208	    targetRowId: string,
209	    newStartTime?: number,
210	    transactionId?: string,
211	  ) => {
212	    let current = dataRef.current;
213	    if (!current) {
214	      return;
215	    }
216	
217	    const enclosingGroup = findEnclosingPinnedGroup(current.config, clipId);
218	    if (enclosingGroup) {
219	      const resolvedTrackId = resolveGroupTrackId(enclosingGroup.group, current.rows);
220	      const resolvedGroup = resolvedTrackId === enclosingGroup.group.trackId
221	        ? enclosingGroup.group
222	        : { ...enclosingGroup.group, trackId: resolvedTrackId };
223	      const sourceTrack = current.tracks.find((track) => track.id === resolvedTrackId);
224	      const targetTrack = current.tracks.find((track) => track.id === targetRowId);
225	      if (!sourceTrack || !targetTrack || sourceTrack.kind !== targetTrack.kind) {
226	        return;
227	      }
