238	      const memberSet = new Set(resolvedGroup.clipIds);
239	      const rowsWithoutGroup = current.rows.map((row) => ({
240	        ...row,
241	        actions: row.actions.filter((a) => !memberSet.has(a.id)),
242	      }));
243	      const snapResult = trySnapToEdge(
244	        rowsWithoutGroup,
245	        targetRowId,
