250	      let finalTargetId = snapResult.snapped
251	        ? targetRowId
252	        : findNearestFreeTrack(
253	            current.tracks,
254	            rowsWithoutGroup,
255	            targetRowId,
256	            sourceTrack.kind,
257	            effectiveGroupStart,
258	            groupDuration,
